**IndexedDbService.cs**:
```csharp
using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbService : ILocalStorageService
{
    private readonly IJSRuntime _jsRuntime;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public IndexedDbService(IJSRuntime jsRuntime)
    {
        _jsRuntime = jsRuntime;
    }

    public async Task InitializeAsync()
    {
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.initialize");
    }

    public async Task SaveSiteAsync(InspectionSite site)
    {
        var data = Serialize(site);
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.addItem", "sites", data);
    }

    public async Task<InspectionSite?> GetSiteAsync(Guid id)
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "sites", id.ToString());
        return result.HasValue ? Deserialize<InspectionSite>(result.Value) : null;
    }

    public async Task<List<InspectionSite>> GetAllSitesAsync()
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement>("indexedDbInterop.getAllItems", "sites");
        return DeserializeList<InspectionSite>(result);
    }

    public async Task DeleteSiteAsync(Guid id)
    {
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.deleteItem", "sites", id.ToString());
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        inspection.LastModified = DateTime.UtcNow;
        var data = Serialize(inspection);
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.addItem", "inspections", data);
    }

    public async Task<Inspection?> GetInspectionAsync(Guid id)
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "inspections", id.ToString());
        return result.HasValue ? Deserialize<Inspection>(result.Value) : null;
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement>("indexedDbInterop.getAllItems", "inspections");
        return DeserializeList<Inspection>(result);
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(Guid siteId)
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement>("indexedDbInterop.getItemsByIndex", "inspections", "siteId", siteId.ToString());
        return DeserializeList<Inspection>(result);
    }

    public async Task DeleteInspectionAsync(Guid id)
    {
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.deleteItem", "inspections", id.ToString());
    }

    public async Task SavePhotoAsync(InspectionPhoto photo)
    {
        var data = Serialize(photo);
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.addItem", "photos", data);
    }

    public async Task<InspectionPhoto?> GetPhotoAsync(Guid id)
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "photos", id.ToString());
        return result.HasValue ? Deserialize<InspectionPhoto>(result.Value) : null;
    }

    public async Task<List<InspectionPhoto>> GetPhotosByInspectionAsync(Guid inspectionId)
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement>("indexedDbInterop.getItemsByIndex", "photos", "inspectionId", inspectionId.ToString());
        return DeserializeList<InspectionPhoto>(result);
    }

    public async Task DeletePhotoAsync(Guid id)
    {
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.deleteItem", "photos", id.ToString());
    }

    public async Task AddToSyncQueueAsync(Guid inspectionId)
    {
        var item = new SyncQueueItem
        {
            InspectionId = inspectionId,
            Status = "Pending"
        };
        var data = Serialize(item);
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.addItem", "syncQueue", data);
    }

    public async Task<List<SyncQueueItem>> GetPendingSyncItemsAsync()
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement>("indexedDbInterop.getItemsByIndex", "syncQueue", "status", "Pending");
        return DeserializeList<SyncQueueItem>(result);
    }

    public async Task UpdateSyncItemStatusAsync(Guid id, SyncStatus status)
    {
        var result = await _jsRuntime.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "syncQueue", id.ToString());
        if (result.HasValue)
        {
            var item = Deserialize<SyncQueueItem>(result.Value);
            if (item != null)
            {
                item.Status = status.ToString();
                var data = Serialize(item);
                await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.addItem", "syncQueue", data);
            }
        }
    }

    public async Task RemoveFromSyncQueueAsync(Guid id)
    {
        await _jsRuntime.InvokeAsync<bool>("indexedDbInterop.deleteItem", "syncQueue", id.ToString());
    }

    private static object Serialize<T>(T item)
    {
        var json = JsonSerializer.Serialize(item, JsonOptions);
        return JsonSerializer.Deserialize<JsonElement>(json, JsonOptions);
    }

    private static T? Deserialize<T>(JsonElement element)
    {
        return JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions);
    }

    private static List<T> DeserializeList<T>(JsonElement element)
    {
        if (element.ValueKind == JsonValueKind.Array)
        {
            return JsonSerializer.Deserialize<List<T>>(element.GetRawText(), JsonOptions) ?? new List<T>();
        }
        return new List<T>();
    }
