            }
        </div>

        <div class="form-group">
            <label class="form-label">Or create new site</label>
            <input type="text" @bind="_newSiteName" placeholder="New site name" class="form-input" />
            <input type="text" @bind="_newSiteAddress" placeholder="Site address" class="form-input" style="margin-top: 8px;" />
        </div>

        <button class="btn-primary-large" @onclick="StartInspection" disabled="@(!CanStart)">
            Start Inspection
        </button>
    </div>
</div>

@code {
    private List<InspectionSite>? _sites;
    private string _inspectorName = string.Empty;
    private string _selectedSiteId = string.Empty;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    private bool CanStart => !string.IsNullOrWhiteSpace(_inspectorName) &&
        (!string.IsNullOrWhiteSpace(_selectedSiteId) || !string.IsNullOrWhiteSpace(_newSiteName));

    protected override async Task OnInitializedAsync()
    {
        await LocalStorage.InitializeAsync();
        _sites = await LocalStorage.GetAllSitesAsync();
    }

    private async Task StartInspection()
    {
        if (!CanStart) return;

        InspectionSite site;

        if (!string.IsNullOrWhiteSpace(_newSiteName))
        {
            site = new InspectionSite
            {
                Name = _newSiteName,
                Address = _newSiteAddress
            };
            await LocalStorage.SaveSiteAsync(site);
        }
        else
        {
            var siteId = Guid.Parse(_selectedSiteId);
            site = await LocalStorage.GetSiteAsync(siteId) ?? new InspectionSite { Id = siteId, Name = "Unknown" };
        }

        var inspection = new Inspection
        {
            SiteId = site.Id,
            SiteName = site.Name,
            InspectorName = _inspectorName,
            Date = DateTime.UtcNow
        };

        // Populate checklist from templates
        foreach (var category in ChecklistTemplates.GetDefaultCategories())
        {
            foreach (var description in category.Value)
            {
                inspection.ChecklistItems.Add(new ChecklistItem
                {
                    InspectionId = inspection.Id,
                    Category = category.Key,
                    Description = description
                });
            }
        }

        await LocalStorage.SaveInspectionAsync(inspection);
        Navigation.NavigateTo($"/checklist/{inspection.Id}");
    }
}
