            <button class="btn-secondary" @onclick="SaveDraft">Save Draft</button>
            <button class="btn-primary-large" @onclick="CompleteInspection">Complete Inspection</button>
        </div>
    }
</div>

@code {
    [Parameter] public Guid InspectionId { get; set; }

    private Inspection? _inspection;

    protected override async Task OnInitializedAsync()
    {
        await LocalStorage.InitializeAsync();
        _inspection = await LocalStorage.GetInspectionAsync(InspectionId);
    }

    private async Task SetStatus(ChecklistItem item, ChecklistStatus status)
    {
        item.Status = item.Status == status ? ChecklistStatus.Unchecked : status;
        await SaveInspection();
    }

    private int GetCheckedCount() => _inspection?.ChecklistItems.Count(i => i.Status != ChecklistStatus.Unchecked) ?? 0;

    private double GetProgressPercent()
    {
        if (_inspection == null || _inspection.ChecklistItems.Count == 0) return 0;
        return (double)GetCheckedCount() / _inspection.ChecklistItems.Count * 100;
    }

    private async Task SaveDraft()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Draft;
        await SaveInspection();
        Navigation.NavigateTo("/");
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Completed;
        await SaveInspection();
        await SyncService.QueueForSyncAsync(_inspection.Id);
        Navigation.NavigateTo($"/inspection/{_inspection.Id}");
    }

    private async Task SaveInspection()
    {
        if (_inspection != null)
        {
            await LocalStorage.SaveInspectionAsync(_inspection);
        }
    }
}
