## 17. Create service-worker.js

Create `/tmp/sv-ff562d2d951c40baa83efe4f4b7c7cfc/SiteInspector/SiteInspector.Client/wwwroot/service-worker.js`:

```javascript
// Development service worker - does basic caching
const CACHE_NAME = 'site-inspector-v1';
const OFFLINE_URLS = [
    '/',
    '/css/app.css',
    '/js/indexedDb.js',
    '/js/connectivity.js'
];

self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => cache.addAll(OFFLINE_URLS))
    );
    self.skipWaiting();
});

self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys().then(keys =>
            Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
        )
    );
    self.clients.claim();
});

self.addEventListener('fetch', event => {
    if (event.request.method !== 'GET') return;
    event.respondWith(
        fetch(event.request)
            .then(response => {
                const clone = response.clone();
                caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                return response;
            })
            .catch(() => caches.match(event.request))
    );
});
```

## 18. Create service-worker.published.js

Create `/tmp/sv-ff562d2d951c40baa83efe4f4b7c7cfc/SiteInspector/SiteInspector.Client/wwwroot/service-worker.published.js`:

```javascript
// Production service worker with Blazor framework caching
const CACHE_NAME = 'site-inspector-v1';

self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => 
            cache.addAll([
                '/',
                '/css/app.css',
                '/js/indexedDb.js',
                '/js/connectivity.js',
                '/manifest.json'
            ])
        )
    );
    self.skipWaiting();
});

self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys().then(keys =>
            Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
        )
    );
    self.clients.claim();
});

self.addEventListener('fetch', event => {
    if (event.request.method !== 'GET') return;

    const url = new URL(event.request.url);

    // Cache-first for static assets
    if (url.pathname.startsWith('/_framework/') || 
        url.pathname.startsWith('/css/') || 
        url.pathname.startsWith('/js/')) {
        event.respondWith(
            caches.match(event.request).then(cached => {
                if (cached) return cached;
                return fetch(event.request).then(response => {
                    const clone = response.clone();
                    caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                    return response;
                });
            })
        );
        return;
    }

    // Network-first for API calls and pages
    event.respondWith(
        fetch(event.request)
            .then(response => {
                const clone = response.clone();
                caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                return response;
            })
            .catch(() => caches.match(event.request))
    );
});
```

