using System.Text.Json;
using SiteInspector.Client.Pages;
using SiteInspector.Components;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents();

var app = builder.Build();

if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}

app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(SiteInspector.Client._Imports).Assembly);

// Sync API endpoints
var syncedInspections = new List<JsonElement>();
var syncedPhotos = new List<JsonElement>();

app.MapPost("/api/sync/inspections", (JsonElement inspection) =>
{
    syncedInspections.Add(inspection);
    return Results.Ok(new { success = true, id = Guid.NewGuid() });
});

app.MapPost("/api/sync/photos", (JsonElement photo) =>
{
    syncedPhotos.Add(photo);
    return Results.Ok(new { success = true });
});

app.MapGet("/api/sync/status", () =>
{
    return Results.Ok(new
    {
        inspectionCount = syncedInspections.Count,
        photoCount = syncedPhotos.Count,
        lastSync = DateTime.UtcNow
    });
});

app.Run();
```

