+using System.Net.Http.Json;
+using SiteInspector.Client.Models;
+
+namespace SiteInspector.Client.Services;
+
+public class SyncService : ISyncService
+{
+    private readonly ILocalStorageService _localStorage;
+    private readonly IConnectivityService _connectivity;
+    private readonly HttpClient _httpClient;
+
+    public SyncService(ILocalStorageService localStorage, IConnectivityService connectivity, HttpClient httpClient)
+    {
+        _localStorage = localStorage;
+        _connectivity = connectivity;
+        _httpClient = httpClient;
+    }
+
+    public async Task<bool> SyncPendingAsync()
+    {
+        if (!_connectivity.IsOnline) return false;
+
+        var pendingItems = await _localStorage.GetPendingSyncItemsAsync();
+        var allSuccess = true;
+
+        foreach (var item in pendingItems)
+        {
+            try
+            {
+                await _localStorage.UpdateSyncItemStatusAsync(item.Id, SyncStatus.Syncing);
+                var inspection = await _localStorage.GetInspectionAsync(item.InspectionId);
+                if (inspection == null)
+                {
+                    await _localStorage.RemoveFromSyncQueueAsync(item.Id);
+                    continue;
+                }
+
+                var response = await _httpClient.PostAsJsonAsync("/api/sync/inspections", inspection);
+                if (response.IsSuccessStatusCode)
+                {
+                    var photos = await _localStorage.GetPhotosByInspectionAsync(item.InspectionId);
+                    foreach (var photo in photos)
+                    {
+                        await _httpClient.PostAsJsonAsync("/api/sync/photos", photo);
+                    }
+
+                    inspection.Status = InspectionStatus.Synced;
+                    await _localStorage.SaveInspectionAsync(inspection);
+                    await _localStorage.RemoveFromSyncQueueAsync(item.Id);
+                }
+                else
+                {
+                    await _localStorage.UpdateSyncItemStatusAsync(item.Id, SyncStatus.Failed);
+                    allSuccess = false;
+                }
+            }
+            catch
+            {
+                await _localStorage.UpdateSyncItemStatusAsync(item.Id, SyncStatus.Failed);
+                allSuccess = false;
+            }
+        }
+
+        return allSuccess;
+    }
+
+    public async Task QueueForSyncAsync(Guid inspectionId)
+    {
+        await _localStorage.AddToSyncQueueAsync(inspectionId);
+        if (_connectivity.IsOnline)
+        {
+            await SyncPendingAsync();
+        }
+    }
+
+    public async Task<int> GetPendingCountAsync()
+    {
+        var items = await _localStorage.GetPendingSyncItemsAsync();
+        return items.Count;
+    }
+}
+

