@page "/"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject ILocalStorageService LocalStorage
@inject ISyncService SyncService
@inject IConnectivityService Connectivity
@inject NavigationManager Navigation

<div class="page-container">
    <div class="page-header">
        <h1>Site Inspector</h1>
        <div class="connectivity-badge @(Connectivity.IsOnline ? "online" : "offline")">
            @(Connectivity.IsOnline ? "● Online" : "● Offline")
        </div>
    </div>

    <div class="action-buttons">
        <button class="btn-primary-large" @onclick="StartNewInspection">
            + New Inspection
        </button>
    </div>

    @if (_pendingSyncCount > 0)
    {
        <div class="sync-banner">
            <span>@_pendingSyncCount inspection(s) pending sync</span>
            <button class="btn-sync" @onclick="ManualSync" disabled="@_isSyncing">
                @(_isSyncing ? "Syncing..." : "Sync Now")
            </button>
        </div>
    }

    <h2 class="section-title">Recent Inspections</h2>

    @if (_inspections == null)
    {
        <p class="loading">Loading...</p>
    }
    else if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections yet.</p>
            <p>Tap "New Inspection" to get started.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.LastModified).Take(10))
            {
                <div class="inspection-card" @onclick="() => ViewInspection(inspection.Id)">
                    <div class="card-header">
                        <span class="site-name">@inspection.SiteName</span>
                        <span class="status-badge status-@inspection.Status.ToString().ToLower()">@inspection.Status</span>
                    </div>
                    <div class="card-body">
                        <span class="inspector">@inspection.InspectorName</span>
                        <span class="date">@inspection.Date.ToString("MMM dd, yyyy")</span>
                    </div>
                    <div class="card-footer">
                        @{ var completed = inspection.ChecklistItems.Count(i => i.Status != ChecklistStatus.Unchecked); }
                        <span>@completed / @inspection.ChecklistItems.Count items checked</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private List<Inspection>? _inspections;
    private int _pendingSyncCount;
    private bool _isSyncing;

    protected override async Task OnInitializedAsync()
    {
        await LocalStorage.InitializeAsync();
        await LoadData();
        Connectivity.ConnectivityChanged += OnConnectivityChanged;
    }

    private async Task LoadData()
    {
        _inspections = await LocalStorage.GetAllInspectionsAsync();
        _pendingSyncCount = await SyncService.GetPendingCountAsync();
    }

    private void StartNewInspection()
    {
        Navigation.NavigateTo("/new-inspection");
    }

    private void ViewInspection(Guid id)
    {
        Navigation.NavigateTo($"/inspection/{id}");
    }

    private async Task ManualSync()
    {
        _isSyncing = true;
        StateHasChanged();
        await SyncService.SyncPendingAsync();
        await LoadData();
        _isSyncing = false;
        StateHasChanged();
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await SyncService.SyncPendingAsync();
            await LoadData();
        }
        await InvokeAsync(StateHasChanged);
    }
}

