@page "/sites"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject ILocalStorageService LocalStorage
@inject NavigationManager Navigation

<div class="page-container">
    <div class="page-header">
        <h1>Sites</h1>
    </div>

    <div class="form-section">
        <h2 class="section-title">Add New Site</h2>
        <div class="form-group">
            <input type="text" @bind="_newSiteName" placeholder="Site name" class="form-input" />
        </div>
        <div class="form-group">
            <input type="text" @bind="_newSiteAddress" placeholder="Address" class="form-input" />
        </div>
        <button class="btn-primary-large" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">
            Add Site
        </button>
    </div>

    <h2 class="section-title">All Sites</h2>

    @if (_sites == null)
    {
        <p class="loading">Loading...</p>
    }
    else if (_sites.Count == 0)
    {
        <div class="empty-state">
            <p>No sites added yet.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
            {
                <div class="inspection-card">
                    <div class="card-header">
                        <span class="site-name">@site.Name</span>
                        <button class="btn-delete" @onclick="() => DeleteSite(site.Id)">✕</button>
                    </div>
                    <div class="card-body">
                        <span>@site.Address</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private List<InspectionSite>? _sites;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await LocalStorage.InitializeAsync();
        await LoadSites();
    }

    private async Task LoadSites()
    {
        _sites = await LocalStorage.GetAllSitesAsync();
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new InspectionSite
        {
            Name = _newSiteName,
            Address = _newSiteAddress
        };

        await LocalStorage.SaveSiteAsync(site);
        _newSiteName = string.Empty;
        _newSiteAddress = string.Empty;
        await LoadSites();
    }

    private async Task DeleteSite(Guid id)
    {
        await LocalStorage.DeleteSiteAsync(id);
        await LoadSites();
    }
}

@page "/new-inspection"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject ILocalStorageService LocalStorage
@inject NavigationManager Navigation

<div class="page-container">
    <div class="page-header">
        <h1>New Inspection</h1>
    </div>

    <div class="form-section">
        <div class="form-group">
            <label class="form-label">Inspector Name</label>
            <input type="text" @bind="_inspectorName" placeholder="Your name" class="form-input" />
        </div>

        <div class="form-group">
            <label class="form-label">Select Site</label>
            @if (_sites != null && _sites.Count > 0)
            {
                <select @bind="_selectedSiteId" class="form-input">
                    <option value="">-- Select a site --</option>
                    @foreach (var site in _sites)
                    {
                        <option value="@site.Id">@site.Name - @site.Address</option>
                    }
                </select>
            }
            else
            {
                <p class="hint-text">No sites available. <a href="/sites">Add a site first.</a></p>
            }
        </div>

        <div class="form-group">
            <label class="form-label">Or create new site</label>
            <input type="text" @bind="_newSiteName" placeholder="New site name" class="form-input" />
            <input type="text" @bind="_newSiteAddress" placeholder="Site address" class="form-input" style="margin-top: 8px;" />
        </div>

        <button class="btn-primary-large" @onclick="StartInspection" disabled="@(!CanStart)">
            Start Inspection
        </button>
    </div>
</div>

@code {
    private List<InspectionSite>? _sites;
    private string _inspectorName = string.Empty;
    private string _selectedSiteId = string.Empty;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    private bool CanStart => !string.IsNullOrWhiteSpace(_inspectorName) &&
        (!string.IsNullOrWhiteSpace(_selectedSiteId) || !string.IsNullOrWhiteSpace(_newSiteName));

    protected override async Task OnInitializedAsync()
    {
        await LocalStorage.InitializeAsync();
        _sites = await LocalStorage.GetAllSitesAsync();
    }

    private async Task StartInspection()
    {
        if (!CanStart) return;

        InspectionSite site;

        if (!string.IsNullOrWhiteSpace(_newSiteName))
        {
            site = new InspectionSite
            {
                Name = _newSiteName,
                Address = _newSiteAddress
            };
            await LocalStorage.SaveSiteAsync(site);
        }
        else
        {
            var siteId = Guid.Parse(_selectedSiteId);
            site = await LocalStorage.GetSiteAsync(siteId) ?? new InspectionSite { Id = siteId, Name = "Unknown" };
        }

        var inspection = new Inspection
        {
            SiteId = site.Id,
            SiteName = site.Name,
            InspectorName = _inspectorName,
            Date = DateTime.UtcNow
        };

        // Populate checklist from templates
        foreach (var category in ChecklistTemplates.GetDefaultCategories())
        {
            foreach (var description in category.Value)
            {
                inspection.ChecklistItems.Add(new ChecklistItem
                {
                    InspectionId = inspection.Id,
                    Category = category.Key,
                    Description = description
                });
            }
        }

        await LocalStorage.SaveInspectionAsync(inspection);
        Navigation.NavigateTo($"/checklist/{inspection.Id}");
    }
}

@page "/checklist/{InspectionId:guid}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject ILocalStorageService LocalStorage
@inject ISyncService SyncService
@inject NavigationManager Navigation

<div class="page-container">
    @if (_inspection == null)
    {
        <p class="loading">Loading...</p>
    }
    else
    {
        <div class="page-header">
            <h1>@_inspection.SiteName</h1>
            <span class="subtitle">@_inspection.InspectorName • @_inspection.Date.ToString("MMM dd")</span>
        </div>

        <div class="progress-bar">
            <div class="progress-fill" style="width: @GetProgressPercent()%"></div>
        </div>
        <p class="progress-text">@GetCheckedCount() / @_inspection.ChecklistItems.Count completed</p>

        @foreach (var category in _inspection.ChecklistItems.GroupBy(i => i.Category))
        {
            <div class="checklist-category">
                <h2 class="category-title">@category.Key</h2>
                @foreach (var item in category)
                {
                    <div class="checklist-item">
                        <div class="item-description">@item.Description</div>
                        <div class="item-actions">
                            <button class="status-btn @(item.Status == ChecklistStatus.Pass ? "active-pass" : "")"
                                    @onclick="() => SetStatus(item, ChecklistStatus.Pass)">✓</button>
                            <button class="status-btn @(item.Status == ChecklistStatus.Fail ? "active-fail" : "")"
                                    @onclick="() => SetStatus(item, ChecklistStatus.Fail)">✗</button>
                            <button class="status-btn @(item.Status == ChecklistStatus.NA ? "active-na" : "")"
                                    @onclick="() => SetStatus(item, ChecklistStatus.NA)">N/A</button>
                        </div>
                    </div>
                }
            </div>
        }

        <div class="form-section">
            <div class="form-group">
                <label class="form-label">Notes</label>
                <textarea @bind="_inspection.Notes" class="form-input form-textarea" placeholder="Additional notes..."></textarea>
            </div>
        </div>

        <div class="action-buttons">
            <button class="btn-secondary" @onclick="SaveDraft">Save Draft</button>
            <button class="btn-primary-large" @onclick="CompleteInspection">Complete Inspection</button>
        </div>
    }
</div>

@code {
    [Parameter] public Guid InspectionId { get; set; }

    private Inspection? _inspection;

    protected override async Task OnInitializedAsync()
    {
        await LocalStorage.InitializeAsync();
        _inspection = await LocalStorage.GetInspectionAsync(InspectionId);
    }

    private async Task SetStatus(ChecklistItem item, ChecklistStatus status)
    {
        item.Status = item.Status == status ? ChecklistStatus.Unchecked : status;
        await SaveInspection();
    }

    private int GetCheckedCount() => _inspection?.ChecklistItems.Count(i => i.Status != ChecklistStatus.Unchecked) ?? 0;

    private double GetProgressPercent()
    {
        if (_inspection == null || _inspection.ChecklistItems.Count == 0) return 0;
        return (double)GetCheckedCount() / _inspection.ChecklistItems.Count * 100;
    }

    private async Task SaveDraft()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Draft;
        await SaveInspection();
        Navigation.NavigateTo("/");
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Completed;
        await SaveInspection();
        await SyncService.QueueForSyncAsync(_inspection.Id);
        Navigation.NavigateTo($"/inspection/{_inspection.Id}");
    }

    private async Task SaveInspection()
    {
        if (_inspection != null)
        {
            await LocalStorage.SaveInspectionAsync(_inspection);
        }
    }
}

