                            <button class="status-btn @(item.Status == ChecklistStatus.NA ? "active-na" : "")"
                                    @onclick="() => SetStatus(item, ChecklistStatus.NA)">N/A</button>
                        </div>
                    </div>
                }
            </div>
        }

        <div class="form-section">
            <div class="form-group">
