                <span class="summary-count">@_inspection.ChecklistItems.Count(i => i.Status == ChecklistStatus.Pass)</span>
                <span class="summary-label">Pass</span>
            </div>
            <div class="summary-item fail">
                <span class="summary-count">@_inspection.ChecklistItems.Count(i => i.Status == ChecklistStatus.Fail)</span>
                <span class="summary-label">Fail</span>
            </div>
            <div class="summary-item na">
                <span class="summary-count">@_inspection.ChecklistItems.Count(i => i.Status == ChecklistStatus.NA)</span>
                <span class="summary-label">N/A</span>
            </div>
        </div>

        @if (_inspection.ChecklistItems.Any(i => i.Status == ChecklistStatus.Fail))
        {
            <h2 class="section-title">Failed Items</h2>
            <div class="inspection-list">
                @foreach (var item in _inspection.ChecklistItems.Where(i => i.Status == ChecklistStatus.Fail))
                {
                    <div class="inspection-card fail-card">
                        <div class="card-header">
                            <span class="site-name">@item.Category</span>
                        </div>
                        <div class="card-body">
                            <span>@item.Description</span>
                        </div>
                    </div>
                }
            </div>
        }

        <h2 class="section-title">Notes</h2>
        <div class="form-section">
            <textarea @bind="_inspection.Notes" class="form-input form-textarea" placeholder="Add notes..."></textarea>
            <button class="btn-secondary" @onclick="SaveNotes" style="margin-top:8px;">Save Notes</button>
        </div>

        <h2 class="section-title">Photos (@_photos.Count)</h2>
        <div class="photo-section">
            <PhotoCapture InspectionId="@InspectionId" OnPhotoAdded="LoadPhotos" />

            @if (_photos.Count > 0)
            {
                <div class="photo-grid">
                    @foreach (var photo in _photos)
                    {
                        <div class="photo-card">
                            <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                            <span class="photo-caption">@photo.Caption</span>
                        </div>
                    }
                </div>
            }
        </div>

        <div class="action-buttons">
            @if (_inspection.Status == InspectionStatus.Draft)
            {
                <button class="btn-primary-large" @onclick="@(() => Navigation.NavigateTo($"/checklist/{InspectionId}"))">
                    Continue Checklist
                </button>
            }
