        📷 Take Photo
        <InputFile OnChange="OnFileSelected" accept="image/*" capture="environment" style="display:none;" />
    </label>

    @if (!string.IsNullOrEmpty(_caption) || _isProcessing)
    {
        <div class="photo-preview">
            @if (_isProcessing)
            {
                <p>Processing...</p>
            }
        </div>
    }
</div>

@code {
    [Parameter] public Guid InspectionId { get; set; }
    [Parameter] public EventCallback OnPhotoAdded { get; set; }

    private string _caption = string.Empty;
    private bool _isProcessing;

    private async Task OnFileSelected(InputFileChangeEventArgs e)
    {
        _isProcessing = true;
        StateHasChanged();

        try
        {
            var file = e.File;
            var buffer = new byte[file.Size];
            await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);

            var photo = new InspectionPhoto
            {
                InspectionId = InspectionId,
                FileName = file.Name,
                ContentType = file.ContentType,
                Base64Data = Convert.ToBase64String(buffer),
                Caption = _caption,
                TakenAt = DateTime.UtcNow
            };

            await LocalStorage.SavePhotoAsync(photo);
            _caption = string.Empty;
            await OnPhotoAdded.InvokeAsync();
        }
        finally
        {
            _isProcessing = false;
            StateHasChanged();
        }
    }
}

