    border-color: var(--success);
    color: white;
}

.status-btn.active-fail {
    background: var(--danger);
    border-color: var(--danger);
    color: white;
}

.status-btn.active-na {
    background: var(--gray);
    border-color: var(--gray);
    color: white;
}

.progress-bar {
    width: 100%;
    height: 8px;
    background: #e5e7eb;
    border-radius: 4px;
    overflow: hidden;
    margin-bottom: 4px;
}

.progress-fill {
    height: 100%;
    background: var(--success);
    border-radius: 4px;
    transition: width 0.3s ease;
}

.progress-text {
    font-size: 13px;
    color: var(--gray);
    margin-bottom: 16px;
}

.form-section {
    background: var(--white);
    border-radius: var(--radius);
    padding: 16px;
    box-shadow: var(--shadow);
    margin-bottom: 16px;
}

.form-group {
    margin-bottom: 16px;
}

.form-label {
    display: block;
    font-size: 14px;
    font-weight: 600;
    margin-bottom: 6px;
    color: #374151;
}

.form-input {
    width: 100%;
    padding: 14px;
    font-size: 16px;
    border: 2px solid #e5e7eb;
    border-radius: 8px;
    outline: none;
    transition: border-color 0.2s;
    background: var(--white);
}

.form-input:focus {
    border-color: var(--primary);
}

.form-textarea {
    min-height: 100px;
    resize: vertical;
    font-family: inherit;
}

.summary-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 12px;
    margin-bottom: 16px;
}

.summary-item {
    text-align: center;
    padding: 16px;
    border-radius: var(--radius);
    background: var(--white);
    box-shadow: var(--shadow);
}

.summary-item.pass { border-top: 4px solid var(--success); }
.summary-item.fail { border-top: 4px solid var(--danger); }
.summary-item.na { border-top: 4px solid var(--gray); }

.summary-count {
    display: block;
    font-size: 28px;
    font-weight: 700;
}

.summary-label {
    font-size: 12px;
    color: var(--gray);
    text-transform: uppercase;
}

.detail-section {
    background: var(--white);
    border-radius: var(--radius);
    padding: 16px;
    box-shadow: var(--shadow);
    margin-bottom: 16px;
}

.detail-section p {
    margin: 8px 0;
    font-size: 14px;
}

.fail-card {
    border-left: 4px solid var(--danger);
}

.photo-section {
    margin-bottom: 16px;
}

.photo-btn {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    cursor: pointer;
}

.photo-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 8px;
    margin-top: 12px;
}

.photo-card {
    border-radius: 8px;
    overflow: hidden;
    background: var(--white);
    box-shadow: var(--shadow);
}

.photo-card img {
    width: 100%;
    height: 120px;
    object-fit: cover;
}

.photo-caption {
    display: block;
    padding: 8px;
    font-size: 12px;
    color: var(--gray);
}

.action-buttons {
    display: flex;
    flex-direction: column;
    gap: 12px;
    margin: 16px 0;
}

.empty-state {
    text-align: center;
    padding: 40px 20px;
    color: var(--gray);
}

.loading {
    text-align: center;
    padding: 40px;
    color: var(--gray);
}

.hint-text {
    font-size: 14px;
    color: var(--gray);
}

.hint-text a {
    color: var(--primary);
}

.photo-capture {
    margin-bottom: 12px;
}

.photo-preview {
    margin-top: 8px;
}
